const CONFIG = {
  AIRTABLE_PAT: $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY || "",
  AIRTABLE_BASE_ID: $env.AIRTABLE_BASE_ID || "",
  AIRTABLE_EPISODE_IMAGE_FIELD: $env.AIRTABLE_EPISODE_IMAGE_FIELD || "cover_image",
  AIRTABLE_EPISODE_MEDIA_FIELD: $env.AIRTABLE_EPISODE_MEDIA_FIELD || "media",
};

const request = this.helpers.httpRequest.bind(this.helpers);
const apiKey = String(CONFIG.AIRTABLE_PAT || "").trim();
const baseId = String(CONFIG.AIRTABLE_BASE_ID || "").trim();

if (!apiKey || !baseId) {
  return {
    json: {
      statusCode: 500,
      error: "Airtable config missing in n8n environment",
      code: "airtable_config_missing",
    },
  };
}

const airtable = "https://api.airtable.com/v0/" + baseId;
const headers = { Authorization: "Bearer " + apiKey };
const fields = [
  "number",
  "title",
  "date",
  "place",
  "duration",
  "cover_url",
  "notes",
  "music_url",
  CONFIG.AIRTABLE_EPISODE_IMAGE_FIELD,
  CONFIG.AIRTABLE_EPISODE_MEDIA_FIELD,
];
const fieldParams = fields
  .filter(Boolean)
  .map((field) => "fields%5B%5D=" + encodeURIComponent(field))
  .join("&");

const records = [];
let offset = "";

try {
  do {
    const url =
      airtable +
      "/Episodes?" +
      fieldParams +
      "&sort%5B0%5D%5Bfield%5D=number&sort%5B0%5D%5Bdirection%5D=asc" +
      (offset ? "&offset=" + encodeURIComponent(offset) : "");

    const data = await request({ method: "GET", url, headers, json: true });
    records.push(...(data.records || []));
    offset = data.offset || "";
  } while (offset);
} catch (error) {
  return {
    json: {
      statusCode: 500,
      error: "Airtable episodes list failed: " + (error?.message || String(error)),
      code: "airtable_episodes_failed",
    },
  };
}

const attachmentField = CONFIG.AIRTABLE_EPISODE_IMAGE_FIELD || "cover_image";
const mediaField = CONFIG.AIRTABLE_EPISODE_MEDIA_FIELD || "media";
const mediaFromAttachments = (attachments) =>
  (Array.isArray(attachments) ? attachments : []).map((attachment) => {
    const contentType = String(attachment.type || "");
    return {
      id: attachment.id || "",
      url: attachment.url || "",
      filename: attachment.filename || "media",
      type: contentType.startsWith("video/") ? "video" : contentType.startsWith("image/") ? "image" : "file",
      contentType,
      size: attachment.size || 0,
    };
  });
const episodes = records
  .map((record) => {
    const f = record.fields || {};
    const attachments = Array.isArray(f[attachmentField]) ? f[attachmentField] : [];
    const mediaAttachments = Array.isArray(f[mediaField]) ? f[mediaField] : [];
    return {
      id: String(f.id || record.id),
      number: Number(f.number || 0),
      title: String(f.title || ""),
      date: String(f.date || ""),
      place: String(f.place || ""),
      duration: String(f.duration || ""),
      cover_url: String(attachments[0]?.url || f.cover_url || ""),
      media: mediaFromAttachments(mediaAttachments),
      notes: String(f.notes || ""),
      music_url: String(f.music_url || ""),
    };
  })
  .filter((episode) => episode.title && episode.date && episode.place)
  .sort((a, b) => a.number - b.number || a.date.localeCompare(b.date));

return { json: { episodes } };
